/**
 * DungeonVerbNodes — Auto-generate verb-field spatial nodes for
 * proc-gen dungeon floors (depth ≥3).
 *
 * Hand-authored floors (depth 1 exterior, depth 2 interior) register
 * their verb nodes directly in engine/verb-nodes.js. Dungeon floors
 * are generated by GridGen and don't have authored node lists. This
 * module scans the generated tile grid at floor-load time and
 * registers nodes derived from existing tiles using the reuse
 * strategy in VERB_FIELD_NPC_ROADMAP.md §13.5.
 *
 * Populated nodes are used by reanimated friendly enemies (§15) and
 * any future actor placed on a dungeon floor that carries a verbSet.
 *
 * Layer 3.5 — depends on TILES (Layer 0), VerbNodes (Layer 1),
 *             FloorManager (Layer 3).
 */
var DungeonVerbNodes = (function () {
  'use strict';

  // ── Config ───────────────────────────────────────────────────────

  // Tile → verb-node type lookup. Each mapping reuses existing
  // vocabulary from verb-nodes.js so archetype verbSets keep working
  // without adding new verbs.
  //
  // Built lazily so TILES has loaded before we peek at constants.
  var _tileNodeMap = null;

  function _buildTileNodeMap() {
    if (_tileNodeMap) return _tileNodeMap;
    if (typeof TILES === 'undefined') return null;

    var T = TILES;
    var m = {};

    // Warmth / light — social gathering (reanimated cluster at light).
    if (T.BONFIRE   !== undefined) m[T.BONFIRE]   = 'bonfire';
    if (T.HEARTH    !== undefined) m[T.HEARTH]    = 'bonfire';
    if (T.TORCH_LIT !== undefined) m[T.TORCH_LIT] = 'bonfire';

    // Errands — things to browse / check.
    if (T.BREAKABLE !== undefined) m[T.BREAKABLE] = 'shop_entrance';
    if (T.CHEST     !== undefined) m[T.CHEST]     = 'shop_entrance';

    // Knowledge / signage — info-gathering.
    if (T.BOOKSHELF !== undefined) m[T.BOOKSHELF] = 'bulletin_board';
    if (T.TERMINAL  !== undefined) m[T.TERMINAL]  = 'bulletin_board';

    // Work stations.
    if (T.BAR_COUNTER !== undefined) m[T.BAR_COUNTER] = 'work_station';
    if (T.ANVIL       !== undefined) m[T.ANVIL]       = 'work_station';

    // Rest / sit.
    if (T.BED   !== undefined) m[T.BED]   = 'rest_spot';
    if (T.TABLE !== undefined) m[T.TABLE] = 'bench';

    // Narrative — reanimated drift toward other corpses (kin).
    if (T.CORPSE !== undefined) m[T.CORPSE] = 'rest_spot';

    _tileNodeMap = m;
    return m;
  }

  // Hard cap to avoid runaway scoring loops on large dungeons.
  var MAX_NODES_PER_FLOOR = 40;

  // Minimum rest_spots we guarantee on any dungeon floor — if tile
  // scan produces fewer, we synthesise rest_spots at open walkable
  // tiles so reanimated creatures always have somewhere to orbit.
  var MIN_REST_SPOTS = 2;

  // Minimum Manhattan distance between synthesised rest_spots and
  // any already-registered node — avoids clustering.
  var SYNTH_REST_MIN_DIST = 3;

  // Track floors we've already populated so re-entry (floor cache
  // hit) doesn't double-register nodes.
  var _populated = {};

  // ── Public API ───────────────────────────────────────────────────

  /**
   * Scan the floor's tile grid and register auto-derived verb nodes
   * via VerbNodes.register. Gated on depth ≥ 3 (dungeon floors only).
   * Idempotent — repeated calls for the same floorId are no-ops.
   *
   * @param {string} floorId
   * @param {Object} floorData  — { grid, gridW, gridH, spawn, ... }
   */
  function populate(floorId, floorData) {
    if (!floorId || !floorData || !floorData.grid) return;
    if (_populated[floorId]) return;
    if (_depth(floorId) < 3) return;
    if (typeof VerbNodes === 'undefined') return;

    var tileMap = _buildTileNodeMap();
    if (!tileMap) return;

    var grid = floorData.grid;
    var W    = floorData.gridW;
    var H    = floorData.gridH;

    var newNodes = [];
    var restSpotCount = 0;

    // Pass 1: tile → node scan
    for (var y = 0; y < H && newNodes.length < MAX_NODES_PER_FLOOR; y++) {
      for (var x = 0; x < W && newNodes.length < MAX_NODES_PER_FLOOR; x++) {
        var t = grid[y][x];
        var nodeType = tileMap[t];
        if (!nodeType) continue;

        newNodes.push({
          id:   'dvn_' + floorId + '_' + x + '_' + y,
          type: nodeType,
          x:    x,
          y:    y
        });
        if (nodeType === 'rest_spot') restSpotCount++;
      }
    }

    // Pass 2: synthesise rest_spots on open tiles if the scan left
    // us below the minimum. Reanimated creatures carry a rest verb
    // with high initial need — we must guarantee targets.
    if (restSpotCount < MIN_REST_SPOTS && newNodes.length < MAX_NODES_PER_FLOOR) {
      var synth = _synthesiseRestSpots(
        grid, W, H, newNodes,
        MIN_REST_SPOTS - restSpotCount,
        floorId
      );
      for (var si = 0; si < synth.length; si++) {
        newNodes.push(synth[si]);
      }
    }

    // ── DOC-110 P3 Ch.2 stretch: per-floor override merge ─────
    // Overrides can patch (type/faction/contested), remove, or
    // append nodes before registration. If VerbNodeOverrides is
    // not loaded (sidecar missing), apply() is a no-op via the
    // typeof guard below.
    var finalNodes = newNodes;
    if (typeof VerbNodeOverrides !== 'undefined' && VerbNodeOverrides.apply) {
      finalNodes = VerbNodeOverrides.apply(floorId, newNodes);
    }

    if (finalNodes.length > 0) {
      VerbNodes.register(floorId, finalNodes);
    }

    _populated[floorId] = true;

    if (typeof console !== 'undefined' && console.log) {
      var overrideNote = (finalNodes !== newNodes)
        ? ' (' + newNodes.length + ' auto + overrides → ' + finalNodes.length + ')'
        : '';
      console.log('[DungeonVerbNodes] ' + floorId +
        ' → ' + finalNodes.length + ' nodes registered' + overrideNote);
    }
  }

  /**
   * Clear the populated flag for a floor (e.g. when the floor is
   * regenerated from scratch rather than restored from cache).
   * Note: this does NOT remove nodes from VerbNodes — VerbNodes has
   * no unregister. Use sparingly.
   */
  function clearCache(floorId) {
    if (floorId) delete _populated[floorId];
    else _populated = {};
  }

  /**
   * Check whether a floor has already been auto-populated.
   */
  function isPopulated(floorId) {
    return !!_populated[floorId];
  }

  // ── Helpers ──────────────────────────────────────────────────────

  function _depth(floorId) {
    if (!floorId) return 1;
    return floorId.split('.').length;
  }

  /**
   * Find up to `count` open walkable tiles spread apart from each
   * other and from existing nodes. Returns an array of synthesised
   * rest_spot node objects.
   */
  function _synthesiseRestSpots(grid, W, H, existing, count, floorId) {
    var out = [];
    if (count <= 0) return out;

    // Pull existing node positions for distance checks.
    var occupied = [];
    for (var i = 0; i < existing.length; i++) {
      occupied.push({ x: existing[i].x, y: existing[i].y });
    }

    // Scan with a stride so we don't pick neighbouring tiles.
    var stride = 3;
    for (var y = 1; y < H - 1 && out.length < count; y += stride) {
      for (var x = 1; x < W - 1 && out.length < count; x += stride) {
        var t = grid[y][x];
        if (typeof TILES === 'undefined' || !TILES.isWalkable(t)) continue;

        // Distance check against all already-chosen points.
        var ok = true;
        for (var k = 0; k < occupied.length; k++) {
          var dx = occupied[k].x - x;
          var dy = occupied[k].y - y;
          if (Math.abs(dx) + Math.abs(dy) < SYNTH_REST_MIN_DIST) {
            ok = false;
            break;
          }
        }
        if (!ok) continue;

        out.push({
          id:   'dvn_' + floorId + '_rest_' + x + '_' + y,
          type: 'rest_spot',
          x:    x,
          y:    y
        });
        occupied.push({ x: x, y: y });
      }
    }

    return out;
  }

  return Object.freeze({
    populate:    populate,
    clearCache:  clearCache,
    isPopulated: isPopulated
  });
})();
